import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule, ActivatedRoute } from '@angular/router';
import { FormsModule } from '@angular/forms';
import { ExamsService } from '../../services';
import { Exam, ExamQuestion, ExamSubmission, ExamResult } from '../../models';

@Component({
  selector: 'app-exam-detail',
  standalone: true,
  imports: [CommonModule, RouterModule, FormsModule],
  templateUrl: './exam-detail.component.html',
  styleUrls: ['./exam-detail.component.scss']
})
export class ExamDetailComponent implements OnInit {
  exam: Exam | null = null;
  questions: ExamQuestion[] = [];
  answers: { [key: string]: string } = {};
  timeRemaining: number = 0;
  isStarted = false;
  isSubmitted = false;
  result: ExamResult | null = null;

  constructor(
    private route: ActivatedRoute,
    private examsService: ExamsService
  ) {}

  ngOnInit() {
    const examId = this.route.snapshot.paramMap.get('id');
    if (examId) {
      this.loadExam(examId);
    }
  }

  loadExam(examId: string) {
    this.examsService.getExamById(examId).subscribe(exam => {
      this.exam = exam;
    });

    this.examsService.getExamQuestions(examId).subscribe(questions => {
      this.questions = questions;
    });
  }

  startExam() {
    if (this.exam && this.exam.duration) {
      this.isStarted = true;
      this.timeRemaining = this.exam.duration * 60; // Convert to seconds
      this.startTimer();
    }
  }

  startTimer() {
    setInterval(() => {
      if (this.timeRemaining > 0) {
        this.timeRemaining--;
      } else {
        this.submitExam();
      }
    }, 1000);
  }

  submitExam() {
    if (!this.exam) return;

    const submission: ExamSubmission = {
      answers: Object.entries(this.answers).map(([questionId, answer]) => ({
        questionId,
        answer
      }))
    };

    this.examsService.submitExam(this.exam.id, submission).subscribe(result => {
      this.result = result;
      this.isSubmitted = true;
    });
  }

  formatTime(seconds: number): string {
    const minutes = Math.floor(seconds / 60);
    const remainingSeconds = seconds % 60;
    return `${minutes}:${remainingSeconds.toString().padStart(2, '0')}`;
  }
}
<div class="min-h-screen bg-gray-50 py-8">
  <div class="max-w-4xl mx-auto px-4">
    <!-- Exam Header -->
    <div *ngIf="exam" class="bg-white rounded-lg shadow-lg p-6 mb-6">
      <h1 class="text-3xl font-bold text-gray-900 mb-4">{{ exam.title }}</h1>
      <div class="grid md:grid-cols-4 gap-4 text-sm text-gray-600">
        <div><strong>Duration:</strong> {{ exam.duration }} minutes</div>
        <div><strong>Questions:</strong> {{ exam.questionCount }}</div>
        <div><strong>Total Marks:</strong> {{ exam.totalMarks }}</div>
        <div><strong>Passing Marks:</strong> {{ exam.passingMarks }}</div>
      </div>
    </div>

    <!-- Start Exam -->
    <div *ngIf="!isStarted && !isSubmitted" class="text-center py-12">
      <div class="bg-white rounded-lg shadow-lg p-8 max-w-md mx-auto">
        <h2 class="text-2xl font-bold text-gray-900 mb-4">Ready to start?</h2>
        <p class="text-gray-600 mb-6">You have {{ exam?.duration || 0 }} minutes to complete this exam.</p>
        <button (click)="startExam()" class="btn-gradient">
          Start Exam
        </button>
      </div>
    </div>

    <!-- Exam Questions -->
    <div *ngIf="isStarted && !isSubmitted">
      <!-- Timer -->
      <div class="bg-white rounded-lg shadow-lg p-4 mb-6 text-center">
        <div class="text-2xl font-bold" [class]="timeRemaining < 300 ? 'text-red-600' : 'text-gray-900'">
          Time Remaining: {{ formatTime(timeRemaining) }}
        </div>
      </div>

      <!-- Questions -->
      <div class="space-y-6">
        <div *ngFor="let question of questions; let i = index" 
             class="bg-white rounded-lg shadow-lg p-6">
          <h3 class="text-lg font-semibold text-gray-900 mb-4">
            {{ i + 1 }}. {{ question.question }}
          </h3>

          <!-- Multiple Choice -->
          <div *ngIf="question.type === 'multiple_choice'" class="space-y-3">
            <div *ngFor="let option of question.options; let j = index" class="flex items-center">
              <input 
                type="radio" 
                [name]="'question-' + question.id"
                [value]="option"
                [(ngModel)]="answers[question.id]"
                class="mr-3">
              <label>{{ option }}</label>
            </div>
          </div>

          <!-- True/False -->
          <div *ngIf="question.type === 'true_false'" class="space-y-3">
            <div class="flex items-center">
              <input 
                type="radio" 
                [name]="'question-' + question.id"
                value="true"
                [(ngModel)]="answers[question.id]"
                class="mr-3">
              <label class="mr-6">True</label>
              <input 
                type="radio" 
                [name]="'question-' + question.id"
                value="false"
                [(ngModel)]="answers[question.id]"
                class="mr-3">
              <label>False</label>
            </div>
          </div>

          <!-- Short Answer -->
          <div *ngIf="question.type === 'short_answer'">
            <textarea 
              [(ngModel)]="answers[question.id]"
              placeholder="Type your answer here..."
              class="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-primary-500"
              rows="4"></textarea>
          </div>
        </div>
      </div>

      <!-- Submit Button -->
      <div class="text-center mt-8">
        <button (click)="submitExam()" class="btn-gradient">
          Submit Exam
        </button>
      </div>
    </div>

    <!-- Results -->
    <div *ngIf="isSubmitted && result" class="text-center py-12">
      <div class="bg-white rounded-lg shadow-lg p-8 max-w-md mx-auto">
        <div class="mb-6">
          <div class="text-6xl font-bold gradient-text mb-2">
            {{ result.percentage }}%
          </div>
          <div class="text-2xl" [class]="result.passed ? 'text-green-600' : 'text-red-600'">
            {{ result.passed ? 'PASSED!' : 'FAILED' }}
          </div>
        </div>

        <div class="grid grid-cols-2 gap-4 text-sm text-gray-600 mb-6">
          <div><strong>Score:</strong> {{ result.obtainedMarks }}/{{ result.totalMarks }}</div>
          <div><strong>Percentage:</strong> {{ result.percentage }}%</div>
        </div>

        <a [routerLink]="['/exams']" class="btn-gradient">
          Back to Exams
        </a>
      </div>
    </div>
  </div>
</div>
